import{_ as t,b as a,a as i,d as r,c as s}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as n,o,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"OCR et reconnaissance de texte","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/ocr.md","filePath":"fr-FR/Other/ocr.md","lastUpdated":1781962217000}'),c={name:"fr-FR/Other/ocr.md"};function u(p,e,h,m,f,g){return o(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="ocr-et-reconnaissance-de-texte" tabindex="-1">OCR et reconnaissance de texte <a class="header-anchor" href="#ocr-et-reconnaissance-de-texte" aria-label="Permalink to &quot;OCR et reconnaissance de texte&quot;">​</a></h1><p>L’OCR reconnaît du texte dans les images, PDF et documents Word afin de faciliter la recherche et la vérification de contenu.</p><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="Paramètres OCR" loading="lazy"></p><h2 id="ce-que-cela-permet" tabindex="-1">Ce que cela permet <a class="header-anchor" href="#ce-que-cela-permet" aria-label="Permalink to &quot;Ce que cela permet&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonction</th><th>Description</th></tr></thead><tbody><tr><td>OCR d’image</td><td>Lit le texte dans les captures d’écran et photos</td></tr><tr><td>OCR de PDF</td><td>Extrait le texte des fichiers PDF</td></tr><tr><td>OCR de Word</td><td>Lit le contenu de documents Word</td></tr><tr><td>Aide à la recherche</td><td>Rend le texte reconnu utilisable dans la recherche</td></tr><tr><td>Traitement par lot</td><td>Traite des fichiers existants en masse</td></tr></tbody></table><p><img src="'+a+'" alt="Résultat OCR" loading="lazy"></p><h2 id="preparation" tabindex="-1">Préparation <a class="header-anchor" href="#preparation" aria-label="Permalink to &quot;Préparation&quot;">​</a></h2><p>Selon le service OCR utilisé, vous aurez besoin d’une clé API ou d’un token. Renseignez les identifiants demandés dans l’interface.</p><p>Si vous utilisez un service externe comme PaddleOCR, vérifiez que les identifiants sont corrects et qu’il reste du quota.</p><p><img src="'+i+'" alt="Obtenir le token" loading="lazy"></p><h2 id="utilisation" tabindex="-1">Utilisation <a class="header-anchor" href="#utilisation" aria-label="Permalink to &quot;Utilisation&quot;">​</a></h2><ol><li>Activez l’OCR.</li><li>Renseignez la clé du service choisi.</li><li>Enregistrez la configuration.</li><li>Envoyez de nouveaux fichiers ou lancez l’OCR sur des fichiers existants.</li><li>Consultez les résultats dans le détail du fichier ou via la recherche.</li></ol><p><img src="'+r+'" alt="Résultat Word" loading="lazy"></p><p><img src="'+s+'" alt="Reconnaissance PDF" loading="lazy"></p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Les images trop petites, floues ou inclinées réduisent la précision.</li><li>Les gros PDF et documents Word peuvent prendre plus de temps.</li><li>Si le quota de l’API est épuisé, la reconnaissance peut échouer.</li><li>Utilisez l’OCR comme aide ; pour les informations importantes, vérifiez aussi le fichier original.</li></ul>',18)])])}const R=n(c,[["render",u]]);export{b as __pageData,R as default};
